# Permission on Demand (POD) — request temporary elevated permissions
# POD grants just-in-time access to specific actions for a time-bound window

# Step 1: User requests elevated permissions via EPM portal or API
# Step 2: Approver reviews and grants (or auto-grant based on policy)
# Step 3: EPM creates a temporary custom policy/role with the requested actions
# Step 4: After the time window expires, EPM automatically revokes the permission

# Request POD via Graph API
$request = @{
    '@odata.type'    = '#microsoft.graph.scheduledPermissionsRequest'
    requestedPermissions = @{
        '@odata.type' = '#microsoft.graph.awsPermissionsDefinition'
        authorizationSystemInfo = @{
            authorizationSystemId   = '<aws-account-id>'
            authorizationSystemType = 'aws'
        }
        identityReference = @{ id = '<iam-user-id>' }
        permissionsDefinitionAction = @{
            '@odata.type' = '#microsoft.graph.awsActionsPermissionsDefinitionAction'
            actions = @('s3:GetObject', 's3:PutObject')
        }
    }
    justification = 'Temporary access for data migration task #1234'
    scheduleInfo  = @{
        startDateTime = (Get-Date).ToString('o')
        expiration    = @{ type = 'afterDuration'; duration = 'PT4H' }
    }
} | ConvertTo-Json -Depth 10

Invoke-MgGraphRequest -Method POST `
  -Uri 'https://graph.microsoft.com/beta/identityGovernance/permissionsManagement/scheduledPermissionsRequests' `
  -Body $request

# Configure an EPM alert rule for anomalous high-privilege action usage
# Alerts are configured in the EPM portal -> Alerts -> Create alert
# Alert types available via Graph API:

$alertRule = @{
    displayName = 'Detect-Unusual-Delete-Actions'
    severity    = 'high'
    alertConditions = @(
        @{
            operand   = 'actionCategory'
            operator  = 'equals'
            threshold = @{ value = 'Delete' }
        },
        @{
            operand   = 'isFirstUsage'
            operator  = 'equals'
            threshold = @{ value = 'true' }
        }
    )
    notificationChannels = @(
        @{
            notificationChannelType = 'email'
            emailAddresses          = @('secops@contoso.com')
        }
    )
} | ConvertTo-Json -Depth 8

# POST to EPM alert rules endpoint (Graph beta)
Invoke-MgGraphRequest -Method POST `
  -Uri 'https://graph.microsoft.com/beta/identityGovernance/permissionsManagement/permissionsRequestChanges' `
  -Body $alertRule
